head.script:
	scwin.initData = {
		"valInfo" : [
			{id : "planBsnsNm", maxByteLength : 1000, mandatory : true},
			{id : "setcscNm", maxLength : 40, mandatory : true},
			{id : "planFoundngDe", maxByteLength : 8, mandatory : false, number : false},
			{id : "planChrgDeptNm", mandatory : false},
			{id : "planChargerNm", mandatory : false},
			{id : "planEqpCpcty", maxByteLength : 22, mandatory : true, number : true},
			{id : "planAmt", maxByteLength : 22, mandatory : true, number : true},
			{id : "cnstrcEqpCpcty", maxByteLength : 22, mandatory : false, number : false},
			{id : "rmCtnt", maxByteLength : 4000},
		],
		"bPlan" : true,
		"bCntstnInput" : false,
		"ecctcList" : [],
		"radDisplayData" : [
			{"name" : "계획", "tooltip" : "계획 절차 기준으로 조회"},
			{"name" : "건설", "tooltip" : "건설 절차 기준으로 조회"}
		]
	};

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSPB1000000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 조회조건 설정
		scwin.initSearchParam();
		// 사업진행구분 코드 설정
		scwin.initDataSet();
		// 화면 데이터 조회
		scwin.btnInqire_onclick();
	};

	/**
	 * 사업진행구분 코드를 조회 및 세팅한다.
	 * @param
	 * @return
	 */
	scwin.initDataSet = function() {
		var requestData = {
			dmaInqireParam : {
				useYn : "Y",
				clsCd : "ECS_2000"
			}
		};

		var option = {
			action : "zz/cmmncd/retrieveCmmnCd.do",
			reqData : requestData,
			resData : dltCmmnCdList,
			success : "scwin.ecctcCdcallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	scwin.ecctcCdcallback = function() {
		scwin.setCmmnCdTitle(false);
	};

	scwin.setCmmnCdTitle = function(bool) {
		scwin.initData.ecctcList = [];
		var dataList = dltCmmnCdList.getAllJSON();
		var plan = "P0";
		// if (bool) plan = "P1";

		for (data of dataList) {
			var obj = {};
			if (data.cmmnCd.substr(0, 2) == plan || data.cmmnCd.substr(0, 1) == "C") {
				scwin.initData.ecctcList.push(data.cmmnCd);
			}
		}

		scwin.initData.ecctcList.forEach(ecsBsnsPrgsDivCd => {
			var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd.replace("P1", "P0") + "']").id);
			var text = dataList.filter(x=> x.cmmnCd == ecsBsnsPrgsDivCd)[0].cmmnCdNm;
			var textX = 430;
			text = text.split("-");
			titleComp.setLabelTitleText(text[0], "", "", text[1]);
			var len = text[2].length;
			if (len > 12) {
				if (text[2].includes("및")) {
					var textTop = text[2].slice(0, text[2].indexOf("및")+1);
					var textBottom = text[2].slice(text[2].indexOf("및")+2);
					len = textTop.replaceAll(" ", "").length;
					textX = textX - (len * 20);
					titleComp.setLabelText(textTop, textX, 100, textBottom);
				} else {
					len = text[2].replaceAll(" ", "").length;
					textX = textX - (len * 20);
					titleComp.setLabelText(text[2], textX, 100);
				}
			} else {
				len = text[2].replaceAll(" ", "").length;
				textX = textX - (len * 20);
				titleComp.setLabelText(text[2], textX, 100);
			}
		});
	};

	/**
	 * 조회조건 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initSearchParam = function() {
		var thsMon = utilLib.getCurrentDate("yyyyMM");
		var today = utilLib.getCurrentDate();
		var params = $p.getParameter("param");
		if (params && params.year) {
			thsMon = String(params.year) + "01";
			today = String(params.year) + "1231";
			var radTarget = String(params.targetKey || "P").toUpperCase().replace("B", "C");
			radPCBy.setValue(radTarget);
		}
		dmaSearchParam.set("strtDt", thsMon + "01");
		dmaSearchParam.set("endDt", today);
		dmaSearchParam.set("basinCd", "ALL");
		dmaSearchParam.set("setcscCd", "ALL");
		dmaSearchParam.set("gubunCd", "ALL");
		dmaSearchParam.set("prgsSttusCd", "ALL");

		acbBasin.setDisabled(true);
	};

	/**
	 * 화면 초기화에 필요한 로직을 수행한다. (조회 및 신규버튼 클릭 시)
	 * @param
	 * @return
	 */
	scwin.clearScreen = function() {
		grdPlanCnstrcList.removeFocusedCell();
		scwin.grdFocusedRowIndex = null;
		btnList1.setStyle("display", "none");
		scwin.setCmmnCdTitle(false);

		for (var ecsBsnsPrgsDivCd of scwin.initData.ecctcList) {
			if (ecsBsnsPrgsDivCd.substr(0, 2) == "P1") {
				ecsBsnsPrgsDivCd = ecsBsnsPrgsDivCd.replace("P1", "P0");
			}
			//상세 사업추진절차 데이터 초기화
			$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
			//상세 사업추진절차 진행사항 초기화
			var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd + "']").id);
			titleComp.cleanLabelTitleProcess();
		}

		// 체크박스 초기화
		scwin.chkClear();
	};

	/**
	 * 조회 버튼 클릭 이벤트
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		scwin.trCnstrcDtlDisplay(false);
		scwin.clearScreen();
		scwin.inqire();
	};

	/**
	 * 조회조건에 맞게 data를 조회한다.
	 * @param
	 * @return
	 */
	scwin.inqire = function() {
		var strtDate = dmaSearchParam.get("strtDt");
		var endDate = dmaSearchParam.get("endDt");
		var ecsBasinDivCd = dmaSearchParam.get("basinCd");
		var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
		var ntntrsSportYn = dmaSearchParam.get("gubunCd");
		var prgsSttusCd = dmaSearchParam.get("prgsSttusCd");
		var cnd = radPCBy.getValue();

		if (String(strtDate).length != 8 || String(endDate).length != 8) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusMonths(strtDate, endDate) > 12 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "12개월")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년월일이 종료년월일보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00013")[0]);
			return;
		}

		var queryString = `?strtDt=${strtDate}`;
		queryString += `&endDt=${endDate}`;
		queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
		queryString += `&ntntrsSportYn=${ntntrsSportYn}`;
		queryString += `&prgsSttusCd=${prgsSttusCd}`;
		queryString += `&cnd=${cnd}`;

		var option = {
			action : "pb/plancnstrc/retrieve-plan-cnstrc.do" +
				queryString,
			method : "get",
			resData : dltPlanCnstrcList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.inqireCallback = function() {
		spnTotalRow.setValue(dltPlanCnstrcList.getRowCount());

		if (scwin.grdFocusedRowIndex != null) {
			grdPlanCnstrcList.setFocusedCell(scwin.grdFocusedRowIndex, 0);
		} else {
			// 화면 오픈과 동시에 상세보기 항목은 초기화 한다.
			// scwin.btnNew_onclick();
			// 상세보기 비활성화
			dmaPlanCnstrc.setEmpty();
			scwin.initData.bPlan = false;
			scwin.setPlanDisabled();
		}
	};

	/**
	 * 신규버튼 클릭시 dataMap을 초기화 한다.
	 * @param
	 * @return
	 */
	scwin.btnNew_onclick = function() {
		scwin.trPlanDtlDisplay(true);
		scwin.trCnstrcDtlDisplay(false);
		scwin.initData.bPlan = true;
		scwin.setPlanDisabled();
		scwin.clearScreen();
		dmaPlanCnstrc.setEmpty();
		scwin.setCnstrcDisabled(dmaPlanCnstrc.getJSON());
	};

	/**
	 * 수열일 때 상세보기 용량 단위 변경_0926
	 * @param <String> setcscDivCd
	 * @return
	 */
	scwin.disabledBySetcsc = function(setcscDivCd) {
		if (setcscDivCd == "60") {
			spnPlanEqpCpcty1.setStyle("display", "none");
			spnPlanEqpCpcty2.setStyle("display", "inline-block");
			spnCnstrcEqpCpcty1.setStyle("display", "none");
			spnCnstrcEqpCpcty2.setStyle("display", "inline-block");
		} else {
			spnPlanEqpCpcty1.setStyle("display", "inline-block");
			spnPlanEqpCpcty2.setStyle("display", "none");
			spnCnstrcEqpCpcty1.setStyle("display", "inline-block");
			spnCnstrcEqpCpcty2.setStyle("display", "none");
		}
	};

	scwin.acbSetcscNm_onviewchange = function(info) {
		scwin.disabledBySetcsc(info.newValue);
	};

	/**
	 * 셀을 선택시 해당 내용을 상세내역으로 표출한다.
	 * @param <Int> row
	 * @param <Int> oldRow
	 * @return
	 */
	scwin.grdPlanCnstrcList_onrowindexchange = function(row, oldRow) {
		scwin.acbClerar();
		if (scwin.initData.bPlan) {
			scwin.initData.bPlan = false;
			scwin.setPlanDisabled();
		}
		scwin.initData.bCntstnInput = false;

		scwin.grdFocusedRowIndex = row;
		var rowData = dltPlanCnstrcList.getRowJSON(scwin.grdFocusedRowIndex);

		dmaPlanCnstrc.setJSON(rowData);
		dmaPlanCnstrcOld.setJSON(rowData);
		scwin.setCnstrcDisabled(rowData);

		if (dmaPlanCnstrc.getJSON().cnstrcEsntlId && !dmaPlanCnstrc.getJSON().cmsBsnsCd
			&& !dmaPlanCnstrc.getJSON().cmsPrjctCd && !dmaPlanCnstrc.getJSON().cmsPrjctSqncIdtfr) {
			scwin.btnInputModal_onclick();
		}

		// 소수력 : 20, 태양광 : 40, 수열 : 60
		if (dmaPlanCnstrc.getJSON().ecsSetcscDivCd == "40" || dmaPlanCnstrc.getJSON().ecsSetcscDivCd == "20" || dmaPlanCnstrc.getJSON().ecsSetcscDivCd == "60") {
			btnList1.setStyle("display", "inline-block");
		} else {
			btnList1.setStyle("display", "none");
		}

		scwin.disabledBySetcsc(dmaPlanCnstrc.getJSON().ecsSetcscDivCd);
		// 사업추진절차  title set
		if (dmaPlanCnstrc.getJSON().ecsSetcscDivCd == "60") {
			scwin.setCmmnCdTitle(true);
		} else {
			scwin.setCmmnCdTitle(false);
		}

		//상세 사업추진절차 조회
		if (!rowData.planEsntlId) {
			return;
		}
		scwin.inqireEctcc(rowData.planEsntlId, rowData.cnstrcEsntlId);
	};

	/**
	 * 상세 사업추진절차를 조회한다.
	 * @param
	 * @return
	 */
	scwin.inqireEctcc = function(planEsntlId, cnstrcEsntlId) {
		for (var ecsBsnsPrgsDivCd of scwin.initData.ecctcList) {
			if (ecsBsnsPrgsDivCd.substr(0, 2) == "P1") {
				ecsBsnsPrgsDivCd = ecsBsnsPrgsDivCd.replace("P1", "P0");
			}
			// 상세 사업추진절차 데이터 초기화
			$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
			$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").reform();
		}

		var queryString = "?planEsntlId=" + (planEsntlId || "");
		queryString += "&cnstrcEsntlId=" + (cnstrcEsntlId || "");

		var option = {
			action : "zz/cmmn/retrieve-ectcc.do"
				+ queryString,
			method : "get",
			resData : "",
			success : "scwin.inqireEctccCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 상세 사업추진절차 inqireEctccCallback 실행한다.
	 * @param
	 * @return
	 */
	scwin.inqireEctccCallback = function(resBody) {
		if (resBody.message.code == "success") {
			// 체크박스 초기화
			scwin.chkClear();

			var ecctcList = scwin.initData.ecctcList;
			var dataList = resBody.data;
			var obj = {};
			// obj, 사업추진절차 초기화
			for (var ecsBsnsPrgsDivCd of ecctcList) {
				if (ecsBsnsPrgsDivCd.substr(0, 2) == "P1") {
					ecsBsnsPrgsDivCd = ecsBsnsPrgsDivCd.replace("P1", "P0");
				}
				obj[ecsBsnsPrgsDivCd] = [];
				$p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List").removeAll();
			}

			for (var data of dataList) {
				if (data.ecsBsnsPrgsDivCd.substr(0, 2) == "P1") {
					data.ecsBsnsPrgsDivCd = data.ecsBsnsPrgsDivCd.replace("P1", "P0");
				}
				obj[data.ecsBsnsPrgsDivCd].push(data);
			}

			var bFlag = true;
			var fill = "#8E8E8E";
			[...ecctcList].reverse().forEach(ecsBsnsPrgsDivCd => {
				if (ecsBsnsPrgsDivCd.substr(0, 2) == "P1") {
					ecsBsnsPrgsDivCd = ecsBsnsPrgsDivCd.replace("P1", "P0");
				}
				var dltData = $p.getComponentById($p.id + "dltEctccLnk" + ecsBsnsPrgsDivCd + "List");
				var titleComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " svg[id$='" + ecsBsnsPrgsDivCd + "']").id);
				titleComp.cleanLabelTitleProcess();
				if (!bFlag) {
					// 상세 사업추진절차 라벨 색설정
					titleComp.setLabelTitleProcess(bFlag);
					// 체크 박스 설정
					var idx = ecctcList.indexOf(ecsBsnsPrgsDivCd);
					if (!obj[ecsBsnsPrgsDivCd].length) {
						if (idx != 0) {
							$p.getComponentById("chkPassYn" + (idx)).setValue("Y");
							//$p.getComponentById("chkPassYn" + (idx)).setDisabled(true);
						}
					}
				}
				if (obj[ecsBsnsPrgsDivCd].length > 0) {
					dltData.setJSON(obj[ecsBsnsPrgsDivCd]);
					if (bFlag) {
						// 상세 사업추진절차 라벨 블링크
						titleComp.setLabelTitleProcess(bFlag, true);
						bFlag = false;
					}
				}
			});

			// 체크박스 설정
			scwin.chkDataChecked();

			// 건설 상세보기
			var dltP0310list = dltEctccLnkP0310List.getAllJSON();
			if (dltP0310list.length) {
				scwin.trCnstrcDtlDisplay(true);
			} else {
				scwin.trCnstrcDtlDisplay(false);
			}
		}
	};

	/**
	 * 계획 상세보기 사용 여부 처리
	 * @param scwin.initData.bPlan
	 * @return
	 */
	scwin.setPlanDisabled = function() {
		// 계획 상세보기 사용 여부 처리
		if (scwin.initData.bPlan) {
			ibxPlanBsnsNm.setDisabled(false);
			acbSetcscNm.setDisabled(false);
			ibxPlanEqpCpcty.setDisabled(false);
			ibxPlanAmt.setDisabled(false);
			ibxRmCtnt.setDisabled(false);
			(scwin.initData.valInfo.find(obj => obj.id == "planBsnsNm") || 0).mandatory = true;
			(scwin.initData.valInfo.find(obj => obj.id == "setcscNm") || 0).mandatory = true;
			(scwin.initData.valInfo.find(obj => obj.id == "planEqpCpcty") || 0).mandatory = true;
		} else {
			ibxPlanBsnsNm.setDisabled(true);
			acbSetcscNm.setDisabled(true);
			ibxPlanEqpCpcty.setDisabled(true);
			ibxPlanAmt.setDisabled(true);
			ibxRmCtnt.setDisabled(true);
			(scwin.initData.valInfo.find(obj => obj.id == "planBsnsNm") || 0).mandatory = false;
			(scwin.initData.valInfo.find(obj => obj.id == "setcscNm") || 0).mandatory = false;
			(scwin.initData.valInfo.find(obj => obj.id == "planEqpCpcty") || 0).mandatory = false;
		}
	};

	/**
	 * 건설설비용량 사용 여부 처리, 모달 버튼 숨김 기능 처리
	 * @param json : dma.getJSON()
	 * @return
	 */
	scwin.setCnstrcDisabled = function(json) {
		// 모달 버튼 숨김 기능 처리 (수기등록, 계약조회, 계약수정)
		if (json.cnstrcEsntlId) {
			btnModal.setStyle("display", "none");
			btnEditModal.setStyle("display", "inline-block");

			// 건설설비용량 사용 여부 처리
			ibxCnstrcEqpCpcty.setDisabled(true);
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).mandatory = false;
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).number = false;
		} else {
			btnModal.setStyle("display", "inline-block");
			btnEditModal.setStyle("display", "none");

			if (dltEctccLnkP0310List.getAllJSON().length) {
				ibxCnstrcEqpCpcty.setDisabled(false);
				(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).mandatory = true;
				(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).number = true;
			}
		}
		/*
		// 건설설비용량 사용 여부 처리
		if (!json.cnstrcEsntlId) {
			ibxCnstrcEqpCpcty.setDisabled(true);
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).mandatory = false;
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).number = false;
		} else {
			ibxCnstrcEqpCpcty.setDisabled(false);
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).mandatory = true;
			(scwin.initData.valInfo.find(obj => obj.id == "cnstrcEqpCpcty") || 0).number = true;
		}
		*/
		/*
		// 모달 버튼 숨김 기능 처리 old
		if (json.ordgTit != "null" && json.ordgTit != "") {
			//btnModal.setStyle("display", "none");
			//btnEditModal.setStyle("display", "inline-block");
			btnModal.addClass("btn-disabled");
			btnEditModal.removeClass("btn-disabled");
			btnModal.setDisabled(true);
			btnEditModal.setDisabled(false);
		} else if (json.ordgTit == "") {
			//btnModal.setStyle("display", "inline-block");
			//btnEditModal.setStyle("display", "none");
			btnModal.removeClass("btn-disabled");
			btnEditModal.addClass("btn-disabled");
			btnModal.setDisabled(false);
			btnEditModal.setDisabled(true);
		}
		*/
	};

	/**
	 * 상세보기에 기재한 내용을 수정/저장한다.
	 * @param
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		if(ecsLib.validateInput(grpDtl, scwin.initData.valInfo)) {
			if (scwin.initData.bPlan) {
				// 계획 추가
				ecsLib.saveRsn($p, `${dmaPlanCnstrc.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00321")[0], "scwin.saveConfirmCallback");
			} else {
				// 건설추가
				if (!ecsLib.isObjEqual(dmaPlanCnstrc.getJSON(), dmaPlanCnstrcOld.getJSON()) &&
					dmaPlanCnstrc.getJSON().ordgTit) {
					ecsLib.saveRsn($p, `${dmaPlanCnstrc.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00321")[0], "scwin.saveConfirmCallback");
				} else {
					// 프로세스
					// 저장 하시겠습니까? \n수정사유를 입력하세요.
					comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321")[0], "scwin.saveConfirmCallback");
				}
			}
		}
	};

	/**
	 * 수정/저장 ComfirmCallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		var requestData = {};
		requestData.dmaPlanCnstrc = dmaPlanCnstrc.getJSON();
		requestData.dmaPlanCnstrcOld = dmaPlanCnstrcOld.getJSON();

		var option = {
			action : "",
			reqData : requestData,
			success : "scwin.saveProcess",
			savedToken : true,
			isShowMeg : false
		};

		if (scwin.initData.bPlan) {
			// 계획 추가
			option.action = "pb/plancnstrc/save-plan.do";
			ajaxLib.executeAjax($p, option);
		} else {
			// 건설추가
			option.action = "pb/plancnstrc/save-cnstrc.do";
			// if (dmaPlanCnstrc.getJSON().ordgTit) {
			if (!ecsLib.isObjEqual(dmaPlanCnstrc.getJSON(), dmaPlanCnstrcOld.getJSON()) &&
				dmaPlanCnstrc.getJSON().ordgTit) {
				ajaxLib.executeAjax($p, option);
			} else {
				// 프로세스 수정/저장 확인 및 실행
				scwin.saveProcess();
			}
		}
	};

	/**
	 * 프로세스 수정/저장 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveProcess = function(resBody) {
		if (scwin.initData.bPlan) {
			// 계획
			scwin.saveMsgCallback(resBody);
		} else {
			// 건설
			var ecctcList = scwin.initData.ecctcList;
			var requestData = {};
			dltEctccList.setJSON([], false);

			var isDummyData = false;

			for (ecctc of [...ecctcList].reverse()) {
				// 기존 데이터와 비교 추가 || 삭제
				var list = $p.getComponentById("dltEctccLnk" + ecctc + "List").getModifiedJSON();
				var tempList = list.filter(obj => list.filter(innerObj => obj.rowStatus == "C" && innerObj.rowStatus == "E" && obj.ectccId == innerObj.ectccId).length).flatMap(obj => obj.ectccId);
				list = list.filter(obj => !tempList.includes(obj.ectccId));

				list.forEach((obj, idx) => {
					var newIdx = dltEctccList.insertRow();
					dltEctccList.setRowJSON(newIdx, obj, true);
					dltEctccList.modifyRowStatus(newIdx, obj.rowStatus);
				});

				// 현재 프로세스에 데이터가 있다면 이후 빈 프로세스에 빈 문서 생성 
				if ($p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length) {
					isDummyData = true;
				}
				if (isDummyData) {
					if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length) {
						var ecctcIdx = ecctcList.indexOf(ecctc);
						var lastPlanIdx = ecctcList.filter(obj => obj.includes("P")).length - 1;
						var lastIdx = ecctcList.length - 1;

						var str = "생략";
						var lnkEsntlId = "";
						var drftDe = "";
						var dummyData = {};

						if (ecctcIdx <= lastPlanIdx) {
							str = "계획" + str;
							lnkEsntlId = dmaPlanCnstrc.getJSON().planEsntlId;
							drftDe = scwin.ecctcDraftDeSelector(ecctcIdx);
						} else if (ecctcIdx >= lastPlanIdx + 1) {
							str = "건설" + str;
							lnkEsntlId = dmaPlanCnstrc.getJSON().cnstrcEsntlId;
							//drftDe = scwin.ecctcDraftDeSelector(ecctcIdx, lastPlanIdx + 1);
							drftDe = scwin.ecctcDraftDeSelector(ecctcIdx);
						}

						dummyData.ecsBsnsPrgsDivCd = ecctc;
						dummyData.ectccId = " ";
						dummyData.ectccTit = str;
						dummyData.drftDe = drftDe;
						dummyData.lnkEsntlId = lnkEsntlId;
						dummyData.rowStatus = "C";

						var newIdx = dltEctccList.insertRow();
						dltEctccList.setRowJSON(newIdx, dummyData, true);
						dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
					}
				}

				// 계획 완료 - 데이터가 없고 체크가 되어 있다면 빈 문서 생성
				/*
				var lastPlanIdx = scwin.initData.ecctcList.filter(obj => obj.includes("P")).length - 1;
				if(ecctc == scwin.initData.ecctcList[lastPlanIdx]) {
					if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length 
							&& $p.getComponentById("chkPassYn" + (lastPlanIdx)).getValue() == "Y") {
						var dummyData = {
							ecsBsnsPrgsDivCd : ecctc,
							ectccId : " ",
							ectccTit : "계획완료",
							drftDe : utilLib.getCurrentDate("yyyyMMdd"),
							lnkEsntlId : dmaPlanCnstrc.getJSON().planEsntlId,
							rowStatus : "C"
						}
						var newIdx = dltEctccList.insertRow();
						dltEctccList.setRowJSON(newIdx, dummyData, true);
						dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
					}
				}

				// 건설 완료 - 데이터가 없고 체크가 되어 있다면 빈 문서 생성.
				var lastIdx = scwin.initData.ecctcList.length - 1;
				if(ecctc == scwin.initData.ecctcList[lastIdx]) {
					if (!$p.getComponentById("dltEctccLnk" + ecctc + "List").getAllJSON().length 
							&& $p.getComponentById("chkPassYn" + (lastIdx)).getValue() == "Y") {
						var dummyData = {
							ecsBsnsPrgsDivCd : ecctc,
							ectccId : " ",
							ectccTit : "건설완료",
							drftDe : utilLib.getCurrentDate("yyyyMMdd"),
							lnkEsntlId : dmaPlanCnstrc.getJSON().cnstrcEsntlId,
							rowStatus : "C"
						}
						var newIdx = dltEctccList.insertRow();
						dltEctccList.setRowJSON(newIdx, dummyData, true);
						dltEctccList.modifyRowStatus(newIdx, dummyData.rowStatus);
					}
				}
				*/
			}
			requestData.dltEctccList = dltEctccList.getAllJSON();

			if (dltEctccList.getAllJSON().length) {
				var option = {
					action : "/zz/cmmn/process-ectcc.do",
					reqData : requestData,
					success : "scwin.saveProcessCallback",
					savedToken : true,
					isShowMeg : false
				};
				ajaxLib.executeAjax($p, option);
			} else if (resBody) {
				scwin.saveMsgCallback(resBody);
			} else {
				// 처리할 데이터가 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			}
		}
	};

	/**
	 * 프로세스 수정/저장 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveProcessCallback = function(resBody) {
		// 계획 상세보기 수립일, 담당부서, 담당자 업데이트
		var grdData = $p.getComponentById("grdEctccLnk" + scwin.initData.ecctcList[0] + "List").getAllJSON();
		var data = grdData.find(obj => obj.drftDe == grdData.reduce((maxDate, obj) => Number(obj.drftDe) > maxDate ? obj.drftDe : maxDate, 0));
		var requestData = {
			dmaEctcc : {
				planEsntlId : dmaPlanCnstrc.getJSON().planEsntlId,
				ecsChrgDeptId : "",
				planChargerEmpno : "",
				planFoundngDe : ""
			}
		};

		if (data) {
			requestData.dmaEctcc.ecsChrgDeptId = data.drftDeptCd;
			requestData.dmaEctcc.planChargerEmpno = data.drafterEmpno;
			requestData.dmaEctcc.planFoundngDe = data.drftDe;

			radPCBy.setValue("P");
			dmaSearchParam.set("strtDt", String(data.drftDe.substr(0, 6)) + "01");
			dmaSearchParam.set("endDt", data.drftDe);
		}

		var option = {
			action : "pb/plancnstrc/update-plan.do",
			reqData : requestData,
			success : "scwin.saveMsgCallback",
			savedToken : false,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 수정/저장 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveMsgCallback = function(resBody) {
		comLib.alert($p, resBody.message.code_name);
		// 상세보기 항목은 초기화 한다.
		scwin.btnNew_onclick();
		scwin.inqire();
	};

