	/**
	 * 상세 사업추진절차 문서 등록 버튼 클릭시 모달을 띄운다. 
	 * @param
	 * @return
	 */
	scwin.docModal_onclick = function(idx) {
		var ecctcList = scwin.initData.ecctcList;

		if (!dmaPlanCnstrc.getJSON().planEsntlId) {
			// 선택된 자료가 없습니다.
			return comLib.alert($p, utilLib.getMessage("SCM.INFO.00258")[0]);
		} else if (idx >= ecctcList.indexOf("C0110") && !dmaPlanCnstrc.getJSON().cnstrcEsntlId) {
			// 등록된 건설정보가 없습니다.
			return comLib.alert($p, utilLib.getMessage("ECS.INFO.00201")[0]);
		}

		var planIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("P"))[0]);
		var cnstrcIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("C"))[0]);
		if (idx > planIdx) {
			if (idx < cnstrcIdx) {
				var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[planIdx] + "List").getAllJSON().length;
				if (!grdData) {
					// 계획수립 사업추진절차 문서등록이 필요합니다.
					return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203", "계획수립")[0]);
				}
			} else if (idx == cnstrcIdx) {
				var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[(cnstrcIdx - 1)] + "List").getAllJSON().length;
				if (!grdData) {
					// 계획완료 사업추진절차 문서등록이 필요합니다.
					return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203", "계획완료")[0]);
				}
			} /*else if (idx > cnstrcIdx) {
				var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[cnstrcIdx] + "List").getAllJSON().length;
				if (!grdData) {
					// 건설수립 사업추진절차 문서등록이 필요합니다.
					return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203", "건설수립")[0]);
				}
			} */
		}

		/*
		// 이전 사업추진절차 등록이 필요합니다.
		var preGrdLen = "";
		if (idx == 0) {
			preGrdLen = true;
		} else {
			preGrdLen = $p.getComponentById("grdEctccLnk" + ecctcList[idx - 1] + "List").getAllJSON().length;
		}
		if (idx > 1) {
			if ($p.getComponentById("chkPassYn" + (idx -1)).getValue() == "N") {
				// msg
				if (!preGrdLen) return comLib.alert($p, utilLib.getMessage("ECS.INFO.00200")[0]);
			}
		}
		*/

		// 모달을 띄운다.
		var lnkEsntlId = dmaPlanCnstrc.getJSON().planEsntlId;
		if (idx >= ecctcList.indexOf("C0110")) {
			lnkEsntlId = dmaPlanCnstrc.getJSON().cnstrcEsntlId;
		}

		var dltProcessList = "dltEctccLnk" + ecctcList[idx] + "List";
		var dltData = $p.getComponentById(dltProcessList).getAllJSON();

		var url = "/ui/ecs/pb/ECSPB1200000.xml";
		var dataObj = {
			parnetId : $p.id,
			planEsntlId : dmaPlanCnstrc.getJSON().planEsntlId,
			cnstrcEsntlId : dmaPlanCnstrc.getJSON().cnstrcEsntlId,
			lnkEsntlId : lnkEsntlId,
			idx : idx,
			ecsBsnsPrgsDivCd : ecctcList[idx],
			dltData : dltData
		};

		var options = {
			id : "ECSPB1200000",
			title : "오아시스 기안문서 목록 조회",
			popupName : "에너지 계획/건설_오아시스 기안문서 조회",
			width : 1100,
			height : 710,
			top : 0,
			left : 0,
			modal : true,
			closeAction : "",
			popupParam : dataObj
		};
		comLib.openPopup($p, "ECSPB1200000", url, options);
	};

	/**
	 * 상세 사업추진절차 문서를 삭제한다.
	 * @param
	 * @return
	 */
	scwin.btnDelete_onclick = function(idx) {
		var ecctcList = scwin.initData.ecctcList;
		scwin.dltEctccList = $p.getComponentById($p.id + "dltEctccLnk" + ecctcList[idx] + "List");
		var grd = $p.getComponentById($p.id + "grdEctccLnk" + ecctcList[idx] + "List");
		scwin.grdEctccList = grd;

		var planIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("P"))[0]);
		var cnstrcIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("C"))[0]);

		if (idx == cnstrcIdx || idx == (cnstrcIdx - 1)) {
			if (grd.getAllJSON().length == 1) {
				for (var idx2 = (idx + 1); idx2 < ecctcList.length; idx2++) {
					diffGrd = $p.getComponentById($p.id + "grdEctccLnk" + ecctcList[idx2] + "List").getAllJSON();
					if (diffGrd.length != 0) {
						if (idx == cnstrcIdx) {
							// 건설수립 사업추진절차에 1개 이상의 문서가 등록되어야 합니다.
							//return comLib.alert($p, utilLib.getMessage("ECS.INFO.00204", "건설수립")[0]);
						} else {
							// 계획완료 사업추진절차에 1개 이상의 문서가 등록되어야 합니다.
							return comLib.alert($p, utilLib.getMessage("ECS.INFO.00204", "계획완료")[0]);
						}
					}
				}
			}
		}

		if (idx == planIdx) {
			if (grd.getAllJSON().length == 1) {
				for (var idx2 = (idx + 1); idx2 < ecctcList.length; idx2++) {
					diffGrd = $p.getComponentById($p.id + "grdEctccLnk" + ecctcList[idx2] + "List").getAllJSON();
					if (diffGrd.length != 0) {
						// 계획수립 사업추진절차에 1개 이상의 문서가 등록되어야 합니다.
						return comLib.alert($p, utilLib.getMessage("ECS.INFO.00204", "계획수립")[0]);
					}
				}
			}
		}

		if (grd.getFocusedRowIndex() > -1) {
			// 삭제하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251")[0], "scwin.deleteConfirmEctccCallback");
		} else {
			// 삭제할 자료를 선택한 후 처리하시기 바랍니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00252")[0]);
		}
	};

