	 * @return
	 */
	scwin.btnCmp_onclick = function(idx) {
		var ecctcList = scwin.initData.ecctcList;
		var dltEctccList = $p.getComponentById($p.id + "dltEctccLnk" + ecctcList[idx] + "List");
		var str = "완료";
