		var drftDe = "";
		var planCnstrc = dmaPlanCnstrc.getJSON();

		if (!planCnstrc.planEsntlId) {
			// 선택된 자료가 없습니다.
			return comLib.alert($p, utilLib.getMessage("SCM.INFO.00258")[0]);
		} else if (idx >= ecctcList.indexOf("C0110") && !planCnstrc.cnstrcEsntlId) {
			// 등록된 건설정보가 없습니다.
			return comLib.alert($p, utilLib.getMessage("ECS.INFO.00201", "건설")[0]);
		}

		if (dltEctccList.getAllJSON().length) {
			// {0} 자료(이)가 존재합니다.
			return comLib.alert($p, utilLib.getMessage("SCM.INFO.00044", "")[0]);
		} else {
			var planIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("P"))[0]);
			var cnstrcIdx = ecctcList.indexOf(ecctcList.filter(obj => obj.includes("C"))[0]);
			if (idx < cnstrcIdx) {
				var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[planIdx] + "List").getAllJSON().length;
				if (!grdData) {
					// 계획수립 사업추진절차 문서등록이 필요합니다.
					return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203", "계획수립")[0]);
				}
				str = "계획" + str;
				lnkEsntlId = planCnstrc.planEsntlId;
				drftDe = scwin.ecctcDraftDeSelector(idx);
			} else if (idx > cnstrcIdx) {
				/*
				var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[cnstrcIdx] + "List").getAllJSON().length;
				if (!grdData) {
					// 건설수립 사업추진절차 문서등록이 필요합니다.
					return comLib.alert($p, utilLib.getMessage("ECS.INFO.00203", "건설수립")[0]);
				}
				*/
				str = "건설" + str;
				lnkEsntlId = planCnstrc.cnstrcEsntlId;
				//drftDe = planCnstrc.lastCompetDe || scwin.ecctcDraftDeSelector(idx, cnstrcIdx);
				drftDe = planCnstrc.lastCompetDe || scwin.ecctcDraftDeSelector(idx);

				// 건설 수립 등록
				var cnstrcFoundng = $p.getComponentById("dltEctccLnkC0110List");
				if (cnstrcFoundng.getAllJSON().length < 1) {
					var cnstrcFoundngData = {};
					cnstrcFoundngData.ecsBsnsPrgsDivCd = "C0110";
					cnstrcFoundngData.ectccId = " ";
					cnstrcFoundngData.ectccTit = "건설생략";
					cnstrcFoundngData.drftDe = planCnstrc.strwrkDe || scwin.ecctcDraftDeSelector(idx);
					cnstrcFoundngData.lnkEsntlId = planCnstrc.cnstrcEsntlId
					cnstrcFoundngData.rowStatus = "C";

					var newIdx = cnstrcFoundng.insertRow();
					cnstrcFoundng.setRowJSON(newIdx, cnstrcFoundngData, true);
					cnstrcFoundng.modifyRowStatus(newIdx, cnstrcFoundngData.rowStatus);
				}
			}
			var dummyData = {
				ecsBsnsPrgsDivCd : ecctcList[idx],
				ectccId : " ",
				ectccTit : str,
				drftDe : drftDe,
				lnkEsntlId : lnkEsntlId,
				rowStatus : "C"
			};

			var newIdx = dltEctccList.insertRow();
			dltEctccList.setRowJSON(newIdx, dummyData, true);
		}
	};

