	/**
	 * 계획 상세보기를 표시한다.
	 * @param
	 * @return
	 */
	scwin.trPlanDtlDisplay = function(bool) {
		var str = "";
		if (bool) {
			btnPlanDtl.removeClass("fa-plus");
			btnPlanDtl.addClass("fa-minus");
			btnPlanDtl.setTitle("접기");
		} else {
			if (btnPlanDtl.hasClass("fa-minus")) {
				btnPlanDtl.removeClass("fa-minus");
				btnPlanDtl.addClass("fa-plus");
				btnPlanDtl.setTitle("펼치기");
				str = "none";
			} else {
				btnPlanDtl.removeClass("fa-plus");
				btnPlanDtl.addClass("fa-minus");
				btnPlanDtl.setTitle("접기");
			}
		}

		var planList = document.querySelectorAll("#" + $p.getFrameId() + " .tr-dtl-plan");
		for (var idx = 0; idx < planList.length; idx++) {
			planList[idx].style.display = str;
		}
	};

	/**
	 * 건설 상세보기를 표시한다.
	 * @param undefined, true, false
	 * @return
	 */
	scwin.trCnstrcDtlDisplay = function(bool) {
		var cnstrcList = document.querySelectorAll("#" + $p.getFrameId() + " .tr-dtl-cnstrc");
		var cnstrcViewList = document.querySelectorAll("#" + $p.getFrameId() + " .tr-dtl-cnstrc-view");
		var cnstrcInputList = document.querySelectorAll("#" + $p.getFrameId() + " .tr-dtl-cnstrc-input");
		var str = ["", "none"];
		// 건설 상세보기 접기/펼치기 버튼 기능
		if (bool == undefined) {
			if (btnCnstrcDtl.hasClass("fa-minus")) {
				btnCnstrcDtl.removeClass("fa-minus");
				btnCnstrcDtl.addClass("fa-plus");
				btnCnstrcDtl.setTitle("펼치기");
				for (var idx = 0; idx < cnstrcViewList.length; idx++) {
					cnstrcViewList[idx].style.display = "none";
				}
				for (var idx = 0; idx < cnstrcInputList.length; idx++) {
					cnstrcInputList[idx].style.display = "none";
				}
			} else {
				btnCnstrcDtl.removeClass("fa-plus");
				btnCnstrcDtl.addClass("fa-minus");
				btnCnstrcDtl.setTitle("접기");
				for (var idx = 0; idx < cnstrcViewList.length; idx++) {
					cnstrcViewList[idx].style.display = "none";
				}
				for (var idx = 0; idx < cnstrcInputList.length; idx++) {
					cnstrcInputList[idx].style.display = "none";
				}
				if (!scwin.initData.bCntstnInput) {
					// 건설 view 상세보기 접기/펴기
					for (var idx = 0; idx < cnstrcViewList.length; idx++) {
						cnstrcViewList[idx].style.display = "";
					}
				} else {
					// 건설 input 상세보기 접기/펴기
					for (var idx = 0; idx < cnstrcInputList.length; idx++) {
						cnstrcInputList[idx].style.display = "";
					}
				}
			}
			return;
		}

		// 건설 존재시 건설 상세보기란 보여주기
		if (bool) {
			cnstrcList[0].style.display = "";
			btnCnstrcDtl.removeClass("fa-plus");
			btnCnstrcDtl.addClass("fa-minus");
			btnCnstrcDtl.setTitle("접기");
			for (var idx = 0; idx < cnstrcViewList.length; idx++) {
				cnstrcViewList[idx].style.display = "none";
			}
			for (var idx = 0; idx < cnstrcInputList.length; idx++) {
				cnstrcInputList[idx].style.display = "none";
			}
			if (!scwin.initData.bCntstnInput) {
				// 건설 view 상세보기 접기/펴기
				for (var idx = 0; idx < cnstrcViewList.length; idx++) {
					cnstrcViewList[idx].style.display = "";
				}
			} else {
				// 건설 input 상세보기 접기/펴기
				for (var idx = 0; idx < cnstrcInputList.length; idx++) {
					cnstrcInputList[idx].style.display = "";
				}
			}
		} else {
			cnstrcList[0].style.display = "none";
			for (var idx = 0; idx < cnstrcViewList.length; idx++) {
				cnstrcViewList[idx].style.display = "none";
			}
			for (var idx = 0; idx < cnstrcInputList.length; idx++) {
				cnstrcInputList[idx].style.display = "none";
			}
		}
	};

	/**
	 * 상세 사업추진절차 체크를 초기화한다.
	 * @param
	 * @return
	 */
	scwin.chkClear = function() {
		for (var idx = 1; idx < scwin.initData.ecctcList.length; idx++) {
			$p.getComponentById("chkPassYn" + (idx)).setValue("N");
			// $p.getComponentById("chkPassYn" + (idx)).setDisabled(false);
		}
	};

	/**
	 * 상세 사업추진절차 데이터(생략,완료) 체크를 선택한다..
	 * @param
	 * @return
	 */
	scwin.chkDataChecked = function() {
		var ecctcList = scwin.initData.ecctcList;
		for (var idx = 1; idx < ecctcList.length; idx++) {
			var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
			if (grdData.find(obj => obj.ectccId == " ")) {
				$p.getComponentById("chkPassYn" + (idx)).setValue("Y");
			}
		}
	};

	/**
	 * 상세 사업추진절차 체크박스 이벤트.
	 * @param
	 * @return
	 */
	scwin.chkPassYn_onviewchange = function(info) {
		var idx = this.id.substr(-1);
		var ecctcList = scwin.initData.ecctcList;

		if (!dmaPlanCnstrc.getJSON().planEsntlId) {
			// 선택된 자료가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00258")[0]);
			info.checked = false;
		} else if (idx >= ecctcList.indexOf("C0110") && !dmaPlanCnstrc.getJSON().cnstrcEsntlId) {
			// 등록된 건설정보가 없습니다.
			comLib.alert($p, utilLib.getMessage("ECS.INFO.00201")[0]);
			info.checked = false;
		}

		for (var chkIdx = 1; chkIdx <= idx; chkIdx++) {
			if (chkIdx < ecctcList.length) {
				var list = $p.getComponentById("dltEctccLnk" + ecctcList[chkIdx] + "List").getAllJSON();
				if (list.length == 0) {
					//if (!$p.getComponentById("chkPassYn" + (chkIdx)).getDisabled()) {
						if (info.checked) {
							$p.getComponentById("chkPassYn" + (chkIdx)).setValue("Y");
						} else {
							$p.getComponentById("chkPassYn" + (chkIdx)).setValue("N");
						}
					//}
				}
			}
		}
	};

	/**
	 * 클릭시 사원번호 조회 모달을 띄운다.
	 * @param
	 * @return
	 */
	scwin.ibxEdptChargerNm_onclick = function(e) {
		if ($p.getPopupWindowList().length < 1) {
			var url = "/ui/ecs/zz/ECSUserSearchPopup.xml";
			var dataObj = {
				"dataMap" : dmaPlanCnstrc.getID(),
				"dataKey" : {
					"empNo" : "edptChargerId",
					"empNm" : "edptChargerNm"
				}
			};

			var options = {
				id : "ECSUserSearchPopup",
				title : "사용자 검색",
				popupName : "사용자 검색",
				width : 800,
				height : 600,
				top : 0,
				left : 0,
				modal : true,
				closeAction : "",
				popupParam : dataObj
			};
			comLib.openPopup($p, "ECSUserSearchPopup", url, options);
			// $p.getComponentById($p.getPopupId()).setDisabled(true);
			// $p.getComponentById($p.getFrameId()).setDisabled(true);
		}
	};

	/**
	 * 라디오버튼별 유역 Disabled 처리
	 * @param info
	 */
	scwin.radPCBy_onviewchange = function(info) {
		var radValue = info.value;

		if (radValue == "P") {
			acbBasin.setDisabled(true);
			acbBasin.setSelectedIndex(0);
			dmaSearchParam.set("basinCd", "ALL");
		} else {
			acbBasin.setDisabled(false);
		}
	};

	/**
	 * 상세 사업추진절차 생략/완료 시 이전 프로세스 수립일, 착공일 찾기
	 * @param info
	 * idx : 인덱스
	 * lastIdx : 어디까지 찾을지 경계
	 * @return 수립일, 착공일
	 */
	scwin.ecctcDraftDeSelector = function(idx, lastIdx) {
		idx = idx - 1;
		var ecctcList = scwin.initData.ecctcList;
		var dltProcessList = "dltEctccLnk" + ecctcList[idx] + "List";
		var dltData = $p.getComponentById(dltProcessList).getAllJSON();

		if (!lastIdx) {
			// 계획
			if (dltData.length) {
				return dltData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max , 0);
			} else {
				return scwin.ecctcDraftDeSelector(idx);
			}
		} else {
			// 건설
			if (idx < lastIdx) {
				return utilLib.getCurrentDate("yyyyMMdd");
			}
			if (dltData.length) {
				return dltData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max , 0);
			} else {
				return scwin.ecctcDraftDeSelector(idx, lastIdx);
			}
		}
	};

	/**
	 * 상세 사업추진절차 생략/완료 시 전체 프로세스 수립일, 착공일 찾기
	 * @param info
	 * prgsDivCd : 등록된 프로세스 위치
	 * @return 수립일, 착공일
	 */
	scwin.ecctcDraftDeSelectorAll = function(prgsDivCd) {
		var ecctcList = scwin.initData.ecctcList;
		var ecctcIdx = ecctcList.indexOf(prgsDivCd);
		var lastPlanIdx = ecctcList.filter(obj => obj.includes("P")).length - 1;
		var lastIdx = ecctcList.length - 1;
		var str = "완료";
		var lnkEsntlId = "";
		var drftDe = "";
		var dltData;

		if (ecctcIdx <= lastPlanIdx) {
			var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[lastPlanIdx] + "List").getAllJSON();
			if (grdData.find(obj => obj.ectccId == " ")) {
				dltData = $p.getComponentById("dltEctccLnk" + ecctcList[lastPlanIdx] + "List");
				dltData.removeRow(0);

				str = "계획" + str;
				lnkEsntlId = dmaPlanCnstrc.getJSON().planEsntlId;
				for (var idx = 0; idx < lastPlanIdx; idx++) {
					grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
					if (grdData.length) {
						var data = grdData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max, 0);
						drftDe = drftDe > data ? drft : data;
					}
				}
			} else {
				return;
			}
		} else {
			var grdData = $p.getComponentById("grdEctccLnk" + ecctcList[lastIdx] + "List").getAllJSON();
			if (grdData.find(obj => obj.ectccId == " ")) {
				dltData = $p.getComponentById("dltEctccLnk" + ecctcList[lastIdx] + "List");
				dltData.removeRow(0);

				str = "건설" + str;
				lnkEsntlId = dmaPlanCnstrc.getJSON().cnstrcEsntlId;
				for (var idx = 0; idx < lastIdx; idx++) {
					grdData = $p.getComponentById("grdEctccLnk" + ecctcList[idx] + "List").getAllJSON();
					if (grdData.length) {
						var data = grdData.reduce((max, obj) => obj.drftDe > max ? obj.drftDe : max, 0);
						drftDe = drftDe > data ? drft : data;
					}
				}
			} else {
				return;
			}
		}
		var dummyData = {
			ecsBsnsPrgsDivCd : ecctcList[lastPlanIdx],
			ectccId : " ",
			ectccTit : str,
			drftDe : drftDe,
			lnkEsntlId : lnkEsntlId,
			rowStatus : "C"
		};
		var newIndex = dltData.insertRow();
		dltData.setRowJSON(newIndex, dummyData, true);
	};

	//============================================================================================
	// 엑셀
	//============================================================================================
	/**
	 * 그리드의 내용을 엑셀로 다운로드 한다. 
	 * @return
	 */
	scwin.btnDownExcel_onclick = function() {
		var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
		var spnSubTitleNm = spnSubTitle.getValue();
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 10,
			text 		: `${menuNm}_` + `${spnSubTitleNm}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPlanCnstrcList, {
			fileName : `${menuNm}_` + `${spnSubTitleNm}.xlsx`,
			type : 1,
			autoSizeColumn : true
		}, infoArr);
	};
